/**
 * Type guard to check whether a value is potential date.
 * @public
 */
export function isPotentialDateValue(value: unknown): value is string | number {
  return isNumber(value) || typeof value === 'string';
}

/**
 * Type guard to check whether a value is a number.
 * @public
 */
export function isNumber(value: unknown): value is number {
  return typeof value === 'number' && !isNaN(value) && isFinite(value);
}
